// 将 networkOverrides 合并到 specific 中每个语言的 network 部分
for (const [code, networkData] of Object.entries(networkOverrides)) {
  if (specific[code] && typeof specific[code] === 'object') {
    specific[code].network = deepMerge(specific[code].network || {}, networkData)
  }
}

function deepMerge(base, override) {
  const result = { ...base }
  for (const key of Object.keys(override)) {
    if (typeof override[key] === 'object' && override[key] !== null && !Array.isArray(override[key])) {
      result[key] = deepMerge(base[key] || {}, override[key])
    } else {
      result[key] = override[key]
    }
  }
  return result
}

const outputDir = path.join(__dirname, '../frontend/src/i18n')
const allLangs = { ...languageJson }

for (const [code, name] of Object.entries(allLangs)) {
  let base = null

  if (specific[code] && typeof specific[code] === 'object' && specific[code].nav) {
    base = specific[code]
  } else if (aliasMap[code] && specific[aliasMap[code]]) {
    base = specific[aliasMap[code]]
  } else {
    base = JSON.parse(JSON.stringify(zhCN))
  }

  if (networkOverrides[code]) {
    base.network = deepMerge(base.network || {}, networkOverrides[code])
  }

  const merged = deepMerge(zhCN, base)
  const content = JSON.stringify(merged, null, 2)
  fs.writeFileSync(path.join(outputDir, `${code}.json`), content + '\n', 'utf-8')
  
  const source = specific[code] ? 'written' : (aliasMap[code] ? `alias of ${aliasMap[code]}` : 'fallback')
  const netSource = networkOverrides[code] ? ' + network override' : ''
  console.log(`✓ ${code} (${name}) - ${source}${netSource}`)
}

console.log('\nDone! All language files generated.')